import React from 'react'
import { PersonOverlay } from '@fs/zion-person'
import { useTranslation } from 'react-i18next'
import { useOverlay, InlineButton } from '@fs/zion-ui'

export default function ChatMessageTreePersonLink({ pid }) {
  const [t] = useTranslation()
  const personOverlay = useOverlay()
  const handleClick = (event) => {
    // Don’t open overlay when opening link in new tab
    if (event.ctrlKey || event.metaKey) return

    event.preventDefault()
    event.stopPropagation()
    personOverlay.handleClick(event)
  }

  return (
    <>
      <InlineButton
        onClick={handleClick}
        to={`/tree/person/${pid}`}
        external
        target="_blank"
        description={t('chat.pid-message.description', 'View person details')}
      >
        {pid}
      </InlineButton>
      {(personOverlay.isOpen || personOverlay.transitioning) && (
        <PersonOverlay linksOpenNewTab personId={pid} overlay={personOverlay} />
      )}
    </>
  )
}
