import React, { lazy, Suspense } from 'react'
import PropTypes from 'prop-types'
import { Button, IconButton, useOverlay, ListItem } from '@fs/zion-ui'
import { trackEvent } from '@fs/zion-analytics'
import { NoticeLoading, TreeViewRelationship } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'

const RelationshipViewer = lazy(() => import('./RelationshipViewer'))

/**
 * JSX button that opens the relationship viewer.
 *
 * @param {object} props - The props passed into the element.
 * @param {string} [props.fromId] - The ID of the person to route from. Not currently implemented.
 * @param {string} [props.toId] - The ID of the person to route to.
 * @param {string} [props.relationshipIdType] - The types of IDs passed in.
 * @param {object} [props.eventInfo] - The event specific information for use at RootsTech or other relatives around me events.
 * @param {boolean} [props.disallowSpouses] - do not allow showing spouses
 * @param {boolean} [props.friendRelationship] - Whether this is a friendRelationship. Currently requires a cisId.
 * @param {boolean} [props.hidePortraits] - do not show portraits
 * @param {object|null} [props.relationshipData] - pass in data from useRelationship(). If not supplied, the component will fetch it's own data.
 * @param {string|null} [props.customText] - Text, if supplied, will be used in stead of default.
 * @param {boolean|null} [props.hideIcon] - Hides the icon on the button or list item.
 * @param {object|null} [props.listItemProps] - The props pass to the list item.
 * @param {object|null} [props.buttonProps] - The props passed to the button.
 * @param {object|null} [props.iconAtEnd] - Puts the button or list item icon at the end
 * @returns {HTMLElement} - JSX.
 */
export default function RelationshipViewerButton(props = {}) {
  const {
    relationshipData,
    fromId, // eslint-disable-line no-unused-vars
    toId,
    relationshipIdType,
    hideText,
    asListItem,
    autoOpen,
    disabled,
    disallowSpouses,
    eventInfo,
    friendRelationship,
    hidePortraits,
    customText,
    hideIcon,
    listItemProps,
    buttonProps,
    noLinks,
    iconAtEnd,
  } = props
  const [t] = useTranslation()
  const viewRelationshipOverlay = useOverlay({ initiallyOpen: autoOpen })

  const openRelationshipViewer = (evt) => {
    trackEvent({ event_name: 'open_relationship_viewer' })
    viewRelationshipOverlay.open(evt)
  }

  const Wrapper = hideText ? IconButton : Button
  const wrapperProps = hideText ? {} : { iconAtEnd }
  const iconToUse = !hideIcon ? TreeViewRelationship : null
  const listItemIcon = iconToUse && <ListItem.Icon Icon={viewRelationshipOverlay.isOpen ? NoticeLoading : iconToUse} />
  return (
    <>
      {asListItem ? (
        <ListItem
          {...listItemProps}
          data-testid="relationship-viewer-button"
          onClick={openRelationshipViewer}
          disabled={viewRelationshipOverlay.isOpen || disabled}
          startElement={!iconAtEnd && listItemIcon}
          endElement={iconAtEnd && listItemIcon}
          primaryText={customText || t('relationship-viewer.view-relationship-action')}
        />
      ) : (
        <Wrapper
          {...buttonProps}
          {...wrapperProps}
          data-testid="relationship-viewer-button"
          onClick={openRelationshipViewer}
          disabled={viewRelationshipOverlay.isOpen || disabled}
          Icon={viewRelationshipOverlay.isOpen ? NoticeLoading : iconToUse}
          title={hideText ? customText || t('relationship-viewer.view-relationship-action') : undefined}
        >
          {customText || t('relationship-viewer.view-relationship-action')}
        </Wrapper>
      )}
      {viewRelationshipOverlay.isOpen && (
        <Suspense fallback="">
          {/* fromId={fromId} is currently excluded, until support is added for tree-person-to-tree-person relationships */}
          <RelationshipViewer
            relationshipData={relationshipData}
            toId={toId}
            overlay={viewRelationshipOverlay}
            autoOpen={autoOpen}
            relationshipIdType={relationshipIdType}
            disallowSpouses={disallowSpouses}
            eventInfo={eventInfo}
            friendRelationship={friendRelationship}
            hidePortraits={hidePortraits}
            noLinks={noLinks}
          />
        </Suspense>
      )}
    </>
  )
}

const toIdRequiredIfNoRelationshipDataSupplied = ({ toId, relationshipData }) =>
  !toId &&
  !(relationshipData || relationshipData === null) &&
  new Error(
    'RelationshipViewerButton: prop `toId` is required. Either provide an ID, or use the `relationshipData` prop with the `useRelationship()` hook.'
  )

RelationshipViewerButton.propTypes = {
  /** The Id of the person to view a relationship to. Required if not using useRelationship(). */
  toId: toIdRequiredIfNoRelationshipDataSupplied,

  /** The Id of the person from whom to view a relationship from */
  // fromId: PropTypes.string,

  /** The type of id to be used in determining the relationship to (personId is default) */
  relationshipIdType: PropTypes.oneOf(['cisId', 'contributorId', 'personId']),

  /** Use ListItem instead of Button */
  asListItem: PropTypes.bool,

  /** Whether to automatically open the relationship viewer on load. */
  autoOpen: PropTypes.bool,

  /** Text, if supplied, will be used in stead of default */
  customText: PropTypes.string,

  /** Hide the text and use an icon button instead of the full button */
  hideText: PropTypes.bool,

  /** Do not show spouses and do not allow the user to turn on showing spouses */
  disallowSpouses: PropTypes.bool,

  /** Whether to disable the button. */
  disabled: PropTypes.bool,

  /** The specific information needed to be used for an event (such as RootsTech) including specific information about the relationship path to take. Only the eventId is required. */
  eventInfo: PropTypes.shape({
    eventId: PropTypes.string.isRequired,
    kinshipDescriptor: PropTypes.string,
    commonAncestorId: PropTypes.string,
    commonAncestorCoparentId: PropTypes.string,
  }),

  /** Send a flag through to tree-data that forces recalculation of relationship descriptions */
  friendRelationship: PropTypes.bool,

  /** To hide icon on button */
  hideIcon: PropTypes.bool,

  /** Do not show portraits for people in the relationship */
  hidePortraits: PropTypes.bool,

  /** Puts the icon at the end of button or list item */
  iconAtEnd: PropTypes.bool,

  /** Any props that list item can take can be passed in */
  listItemProps: PropTypes.shape({}),

  /** Any props that button can take can be passed in */
  buttonProps: PropTypes.shape({}),

  /** Removes all external links. Person overlays will not show. **Please contact the TreeWeb team before using this mode.** */
  noLinks: PropTypes.bool,

  /** MUST be the return of useRelationship() hook.
   * You will most likely don't need this.
   * It exists as an option to reduce endpoint calls if you are already needing
   * the data outside of the RelationshipViewer */
  relationshipData: PropTypes.any,
}

RelationshipViewerButton.defaultProps = {
  asListItem: false,
  autoOpen: false,
  disabled: false,
  disallowSpouses: false,
  friendRelationship: false,
  hideText: false,
  iconAtEnd: false,
  listItemProps: {},
  relationshipIdType: 'personId',
}
