import React, { useEffect, useState, type ComponentProps } from 'react'
import { usePerson } from '@fs/zion-person-service'
import { QuickGlanceOverlay, type UseOverlayReturnOptions } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { type PID, type Person, type SummaryPerson, type TdPerson } from '@fs/zion-tree-types'
import PropTypes from 'prop-types'
import PersonOverlaySheetSummary from './PersonOverlaySheetSummary'

type Props = {
  personId: PID
  personObj?: Person | SummaryPerson | TdPerson
  overlay: UseOverlayReturnOptions
  /** If true, all links will open new tabs. */
  linksOpenNewTab?: boolean
  /** Options for displaying a link (Icon, text, onClick, linkName, to, external, target) below the header in the PersonOverlay. */
  subheaderLink?: ComponentProps<typeof PersonOverlaySheetSummary>['subheaderLink']
  /** QuickGlanceOverlay Props that will be passed to the PersonOverlay */
  personOverlayProps?: Omit<
    ComponentProps<typeof QuickGlanceOverlay>,
    'children' | keyof UseOverlayReturnOptions | 'fullscreen' | 'data-testid' | 'aria-label'
  >
  showPQSTag?: boolean
}
/**
 * React person-overlay: the canonical source of truth for how we will display person-overlay elements on the site.
 * @see {@link https://github.com/fs-webdev/zion/blob/master/packages/person/src/internal/PersonOverlay/README.mdx | Person Overlay README}
 *
 * @param {object} props - The props passed into the element, that become destructured into their respective destinations.
 * @param {string} [props.personId] - The person id for the component to fetch information about. This will overwrite any personObj that is passed in. Setting this property will make a network call for the personObj.
 * @param {object} [props.personObj] - A tree-data person to display. If passed in with `props.personId`, this person will be displayed until the data is returned.
 * @param {object} [props.subheaderLink] - Options for displaying a link (Icon, text, onClick, linkName, to, external, target) below the header in the PersonOverlay.
 * @param {object} [props.personOverlayProps] - QuickGlanceOverlay props you want to use such as placement
 * @returns {HTMLElement} - The React element itself.
 */
export default function PersonOverlay({
  personId,
  personObj,
  overlay,
  linksOpenNewTab,
  subheaderLink,
  personOverlayProps,
  showPQSTag = false,
}: Props): JSX.Element {
  const [t] = useTranslation()
  const { isOpen } = overlay
  const [activePersonId, setActivePersonId] = useState<PID | undefined>(undefined)

  useEffect(() => {
    if (isOpen && personId) {
      setActivePersonId(personId)
    }
  }, [isOpen, personId])

  const personObjWithId = personObj ? { ...personObj, id: personId } : undefined
  const displayPerson = usePerson(activePersonId, 'card', personObjWithId)

  const newTabProps = linksOpenNewTab
    ? {
        target: '_blank',
        rel: 'noopener noreferrer',
      }
    : {}

  return (
    <QuickGlanceOverlay
      {...(personOverlayProps ?? {})}
      {...overlay}
      fullscreen
      data-testid="PersonOverlay"
      aria-label={t('person.person-overlay.quick-view-label', { name: displayPerson?.name })}
    >
      <PersonOverlaySheetSummary
        displayPerson={displayPerson}
        newTabProps={newTabProps}
        subheaderLink={subheaderLink}
        linksOpenNewTab={linksOpenNewTab}
        showPQSTag={showPQSTag}
      />
    </QuickGlanceOverlay>
  )
}

